  { name: "Anna", role: "admin", active: true, country: "PL" },
  { name: "Bob", role: "user", active: true, country: "DE" },
  { name: "Cara", role: "admin", active: false, country: "PL" },
  { name: "Dan", role: "admin", active: true, country: "DE" },
  { name: "Eva", role: "user", active: true, country: "PL" },
];

const byRole = byField("role");
const byActive = byField("active");
const byCountry = byField("country");

const isAdmin = byRole("admin");
const isActive = byActive(true);
const isFromPoland = byCountry("PL");

