import React, { useCallback, useState, memo } from "react";

const Child = memo(function Child({ onChange, label }) {
  console.log("Child rendered:", label);
  return <input placeholder={label} onChange={onChange} />;
});

function MyForm() {
  const [form, setForm] = useState({});
  const [count, setCount] = useState(0);

  const handleChangeWithId = useCallback(
    (id) => (event) => {
      const value = event.target.value;

      setForm((prev) => ({
        ...prev,
        [id]: value,
      }));
    },
    []
  );

  return (
    <div>
      <button onClick={() => setCount((c) => c + 1)}>
        rerender {count}
      </button>

      <Child label="Item 1" onChange={handleChangeWithId(1)} />
      <Child label="Item 2" onChange={handleChangeWithId(2)} />
    </div>
  );
}

import React, { useCallback, useState, memo } from "react";

const Child = memo(function Child({ onChange, label }) {
  console.log("Child rendered:", label);
  return <input placeholder={label} onChange={onChange} />;
});

function MyForm() {
  const [form, setForm] = useState({});
  const [count, setCount] = useState(0);

  const handleItem1Change = useCallback((event) => {
    const value = event.target.value;

    setForm((prev) => ({
      ...prev,
      1: value,
    }));
  }, []);

  const handleItem2Change = useCallback((event) => {
    const value = event.target.value;

    setForm((prev) => ({
      ...prev,
      2: value,
    }));
  }, []);

  return (
    <div>
      <button onClick={() => setCount((c) => c + 1)}>
        rerender {count}
      </button>

      <Child label="Item 1" onChange={handleItem1Change} />
      <Child label="Item 2" onChange={handleItem2Change} />
    </div>
  );
}

