const makeLogger = (scope) => (message) => {
  console.log("[" + scope + "] " + message);
};

const logAuth = makeLogger("auth");

logAuth("User signed in");
// [auth] User signed in

const makeUserService = (api) => (log) => async (userId) => {
  log.info(`Loading user ${userId}`);
  return api.getUser(userId);
};

const makeApi = (baseUrl) => (path) => async () => {
  const response = await fetch(baseUrl + path);
  return response.json();
};

const api = makeApi("/api");

const getUsers = api("/users");
const getPosts = api("/posts");

getUsers().then(console.log);
getPosts().then(console.log);

const format = (currency) => (locale) => (precision) => (amount) =>
